INSERT INTO cities (abbreviation, name, images, description) VALUES
('HNO', 'Hà Nội', ARRAY[]::TEXT[], 'Thủ đô nghìn năm văn hiến, trung tâm chính trị, văn hóa và du lịch với di sản phố cổ, hồ và làng nghề.'),
('HPG', 'Hải Phòng', ARRAY[]::TEXT[], 'Thành phố cảng năng động, nổi bật với hoa phượng đỏ, biển Đồ Sơn, Cát Bà và vịnh Lan Hạ.'),
('BNI', 'Bắc Ninh', ARRAY[]::TEXT[], 'Vùng đất Kinh Bắc giàu truyền thống quan họ, chùa tháp cổ, làng nghề và di sản văn hóa lâu đời.'),
('HYE', 'Hưng Yên', ARRAY[]::TEXT[], 'Đất Phố Hiến xưa, nổi bật với văn miếu, đền chùa cổ, nhãn lồng và không gian văn hóa đồng bằng Bắc Bộ.'),
('NBI', 'Ninh Bình', ARRAY[]::TEXT[], 'Vùng cố đô Hoa Lư, nổi tiếng với Tràng An, Tam Cốc, núi đá vôi, hang động và du lịch sinh thái.'),
('QNH', 'Quảng Ninh', ARRAY[]::TEXT[], 'Tỉnh ven biển Đông Bắc, nổi bật với vịnh Hạ Long, Yên Tử, di sản mỏ than và du lịch biển đảo.'),
('DBI', 'Điện Biên', ARRAY[]::TEXT[], 'Vùng đất lịch sử Điện Biên Phủ, có núi rừng Tây Bắc, văn hóa dân tộc và cảnh quan thung lũng Mường Thanh.'),
('LCA', 'Lai Châu', ARRAY[]::TEXT[], 'Tỉnh miền núi Tây Bắc với đèo cao, thác nước, bản làng dân tộc, ruộng bậc thang và văn hóa thổ cẩm.'),
('LCI', 'Lào Cai', ARRAY[]::TEXT[], 'Cửa ngõ Tây Bắc, nổi tiếng với Sa Pa, Fansipan, chợ vùng cao, ruộng bậc thang và bản sắc dân tộc.'),
('SLA', 'Sơn La', ARRAY[]::TEXT[], 'Vùng cao Tây Bắc có cao nguyên Mộc Châu, thủy điện Sơn La, bản làng dân tộc và cảnh quan núi rừng.'),
('CBA', 'Cao Bằng', ARRAY[]::TEXT[], 'Tỉnh biên giới Đông Bắc với thác Bản Giốc, non nước Cao Bằng, hang động và văn hóa Tày Nùng.'),
('LSN', 'Lạng Sơn', ARRAY[]::TEXT[], 'Vùng biên ải nổi bật với Mẫu Sơn, ải Chi Lăng, chợ Kỳ Lừa, hoa hồi và di tích lịch sử.'),
('PTH', 'Phú Thọ', ARRAY[]::TEXT[], 'Đất Tổ Hùng Vương, trung tâm tín ngưỡng cội nguồn, lễ hội Đền Hùng và văn hóa trung du Bắc Bộ.'),
('TNG', 'Thái Nguyên', ARRAY[]::TEXT[], 'Tỉnh trung du nổi tiếng với đồi chè Tân Cương, hồ Núi Cốc, công nghiệp thép và văn hóa các dân tộc.'),
('TQU', 'Tuyên Quang', ARRAY[]::TEXT[], 'Thủ đô khu giải phóng xưa, có Tân Trào, Na Hang, sông Lô, rừng núi và lễ hội Thành Tuyên.'),
('HUE', 'Huế', ARRAY[]::TEXT[], 'Cố đô bên sông Hương, nổi tiếng với quần thể di tích triều Nguyễn, nhã nhạc, ẩm thực và lăng tẩm.'),
('HTI', 'Hà Tĩnh', ARRAY[]::TEXT[], 'Vùng đất miền Trung có núi Hồng Lĩnh, biển Thiên Cầm, di sản văn hóa và truyền thống hiếu học.'),
('NAN', 'Nghệ An', ARRAY[]::TEXT[], 'Quê hương Chủ tịch Hồ Chí Minh, có biển Cửa Lò, Pù Mát, dân ca ví giặm và không gian văn hóa xứ Nghệ.'),
('QTR', 'Quảng Trị', ARRAY[]::TEXT[], 'Vùng đất lịch sử bên vĩ tuyến 17, nổi bật với Thành cổ, cầu Hiền Lương, địa đạo và biển đảo.'),
('THA', 'Thanh Hóa', ARRAY[]::TEXT[], 'Tỉnh Bắc Trung Bộ có Thành nhà Hồ, Lam Kinh, Sầm Sơn, trống đồng Đông Sơn và nhiều cảnh quan đa dạng.'),
('DNG', 'Đà Nẵng', ARRAY[]::TEXT[], 'Thành phố biển miền Trung, nổi tiếng với sông Hàn, cầu Rồng, Ngũ Hành Sơn, Sơn Trà và Bà Nà Hills.'),
('DLA', 'Đắk Lắk', ARRAY[]::TEXT[], 'Trung tâm Tây Nguyên, nổi bật với Buôn Ma Thuột, cà phê, nhà dài Ê Đê, hồ Lắk và văn hóa cồng chiêng.'),
('GLA', 'Gia Lai', ARRAY[]::TEXT[], 'Tỉnh Tây Nguyên có Biển Hồ, núi lửa Chư Đăng Ya, văn hóa cồng chiêng, cà phê và rừng núi bazan.'),
('KHA', 'Khánh Hòa', ARRAY[]::TEXT[], 'Tỉnh duyên hải Nam Trung Bộ, nổi tiếng với Nha Trang, vịnh biển, đảo yến, tháp Chăm và du lịch nghỉ dưỡng.'),
('LDG', 'Lâm Đồng', ARRAY[]::TEXT[], 'Cao nguyên mát lành với Đà Lạt, rừng thông, thác nước, hoa, trà, cà phê và không gian nghỉ dưỡng.'),
('QNG', 'Quảng Ngãi', ARRAY[]::TEXT[], 'Vùng duyên hải miền Trung có đảo Lý Sơn, chứng tích Sơn Mỹ, bãi biển và văn hóa Sa Huỳnh.'),
('HCM', 'Thành phố Hồ Chí Minh', ARRAY[]::TEXT[], 'Đô thị lớn nhất Việt Nam, trung tâm kinh tế, văn hóa, ẩm thực và giải trí sôi động của phía Nam.'),
('DNA', 'Đồng Nai', ARRAY[]::TEXT[], 'Tỉnh công nghiệp Đông Nam Bộ, có sông Đồng Nai, hồ Trị An, rừng Nam Cát Tiên và nhiều điểm sinh thái.'),
('TNI', 'Tây Ninh', ARRAY[]::TEXT[], 'Vùng đất biên giới có núi Bà Đen, Tòa Thánh Cao Đài, hồ Dầu Tiếng và nhiều trải nghiệm tâm linh, sinh thái.'),
('CTH', 'Cần Thơ', ARRAY[]::TEXT[], 'Thủ phủ miền Tây bên sông Hậu, nổi tiếng với chợ nổi Cái Răng, miệt vườn và văn hóa sông nước.'),
('AGI', 'An Giang', ARRAY[]::TEXT[], 'Tỉnh biên giới Tây Nam có Bảy Núi, Châu Đốc, rừng tràm Trà Sư, kênh Vĩnh Tế và văn hóa đa sắc tộc.'),
('CMU', 'Cà Mau', ARRAY[]::TEXT[], 'Mảnh đất cực Nam Tổ quốc, nổi bật với Đất Mũi, rừng ngập mặn, biển đảo và hệ sinh thái sông nước.'),
('DTP', 'Đồng Tháp', ARRAY[]::TEXT[], 'Vùng sen hồng Đồng Tháp Mười, nổi tiếng với Tràm Chim, Sa Đéc, làng hoa và cảnh quan sông nước.'),
('VLG', 'Vĩnh Long', ARRAY[]::TEXT[], 'Tỉnh miệt vườn ven sông Cửu Long, có cù lao, chợ quê, Văn Thánh Miếu và văn hóa sông nước Nam Bộ.')
INSERT INTO city_activity (name, city_abbreviation, images, description, type) VALUES
('Khuê Văn Các', 'HNO', ARRAY['https://dulich3mien.vn/wp-content/uploads/2022/09/Khue-Van-Cac-4.jpg', 'https://hnm.1cdn.vn/2021/08/22/nhipsonghanoi.hanoimoi.com.vn-uploads-images-phananh-2021-08-19-_kvc.jpg', 'https://ik.imagekit.io/tvlk/blog/2022/08/van-mieu-quoc-tu-giam-11.jpg?tr=dpr-2,w-675']::TEXT[], 'Khuê Văn Các là biểu tượng kiến trúc thanh nhã của Văn Miếu, nổi bật với gác vuông hai tầng, mái ngói cổ và ý nghĩa tôn vinh truyền thống hiếu học của Hà Nội.', 'landmarks'),
('Hồ Gươm', 'HNO', ARRAY['https://cdn3.ivivu.com/2022/09/hồ-Gươm-ivivu-2.jpg', 'https://cdn3.ivivu.com/2022/09/hồ-gươm1.jpg', 'https://ik.imagekit.io/tvlk/blog/2022/08/ho-guom-17-1024x683.jpg?tr=dpr-2,w-675']::TEXT[], 'Hồ Gươm nằm giữa trung tâm Hà Nội, gắn với truyền thuyết trả gươm, Tháp Rùa, cầu Thê Húc và không gian mặt nước cổ kính giữa nhịp phố hiện đại.', 'landmarks'),
('Văn Miếu - Quốc Tử Giám', 'HNO', ARRAY['https://ik.imagekit.io/tvlk/blog/2022/08/van-mieu-quoc-tu-giam-1-1024x683.jpg?tr=dpr-2,w-675', 'https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/08/van-mieu-quoc-tu-giam-khue-van-cac.jpg', 'https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/08/van-mieu-quoc-tu-giam.jpg']::TEXT[], 'Văn Miếu - Quốc Tử Giám là công trình tâm linh và kiến trúc nổi bật của Hà Nội, lưu giữ hoa văn, nếp thờ tự và nhiều giá trị văn hóa qua các thế hệ.', 'landmarks'),
('Hoàng thành Thăng Long', 'HNO', ARRAY['https://ik.imagekit.io/tvlk/blog/2022/03/hoang-thanh-thang-long-1.jpg', 'https://static.vinwonders.com/production/hoang-thanh-thang-long-2-768x511.jpg', 'https://media-cdn-v2.laodong.vn/Storage/NewsPortal/2023/5/7/1189286/Anh-Hoang-Thanh-Than-11.jpg']::TEXT[], 'Hoàng thành Thăng Long ghi dấu những lớp lịch sử quan trọng của Hà Nội, với không gian trưng bày, kiến trúc hoặc dấu tích giúp tái hiện ký ức văn hóa địa phương.', 'landmarks'),
('Phố cổ Hà Nội', 'HNO', ARRAY['https://ik.imagekit.io/tvlk/blog/2022/08/pho-co-ha-noi-1-1024x683.jpg?tr=dpr-2,w-675', 'https://travelviet.net/s3_amazon/b72ecb2c-0a63-4371-8af9-c43bb8d16d7a-pho-cojpg.jpg', 'https://statics.vinpearl.com/pho-co-ha-noi-10_1687918089.jpg']::TEXT[], 'Phố cổ Hà Nội phản ánh bản sắc đời sống của Hà Nội, với kiến trúc, hàng quán, nghề truyền thống hoặc nhịp sinh hoạt cộng đồng giàu màu sắc địa phương.', 'landmarks'),
('Thưởng thức đặc sản Hà Nội', 'HNO', ARRAY['https://tieudung.kinhtedothi.vn/upload_images/images/2023/11/30/cha-com-ha-noi.jpg', 'https://ik.imagekit.io/tvlk/blog/2022/09/dac-san-ha-noi-4.jpg?tr=dpr-1.5,h-480,q-40,w-1024', 'https://static.vinwonders.com/production/dac-san-ha-noi-banner.jpg']::TEXT[], 'Thưởng thức đặc sản Hà Nội qua những món ăn dân dã, hương vị địa phương và quán quen của người bản xứ, mang lại cảm giác gần gũi, no đủ và đáng nhớ trong hành trình.', 'activity'),
('Khám phá văn hóa địa phương Hà Nội', 'HNO', ARRAY['https://vstatic.vietnam.vn/vietnam/resource/IMAGE/2025/10/22/1761098945245_dsc_11102025_2449.jpeg', 'https://vov2.vov.vn/sites/default/files/styles/large/public/2022-03/doc-dao-le-hoi-van-hoa-du-lich-ha-noi-20201593134202.jpg', 'https://cdn.attractionsvietnam.com/uploads/gemini/66a3dd3731d21.webp']::TEXT[], 'Khám phá văn hóa Hà Nội qua lễ hội, phong tục, kiến trúc, câu chuyện dân gian và đời sống cộng đồng, giúp du khách cảm nhận sâu hơn về con người và bản sắc địa phương.', 'activity'),
('Chụp ảnh cảnh đẹp Hà Nội', 'HNO', ARRAY['https://tophanoiaz.com/wp-content/uploads/2023/10/hinh-anh-danh-lam-thang-canh-ha-noi_13.jpg', 'https://statics.vinpearl.com/dia-diem-chup-anh-dep-o-ha-noi-1_1680675425.jpg', 'https://ik.imagekit.io/tvlk/blog/2022/08/pho-co-ha-noi-11.jpg']::TEXT[], 'Chụp ảnh cảnh đẹp Hà Nội qua những góc phố, dòng sông, ruộng đồng, núi rừng hoặc di tích nổi bật, lưu lại khoảnh khắc tự nhiên và cảm xúc riêng của chuyến đi.', 'activity'),
('Tham quan làng nghề và chợ địa phương Hà Nội', 'HNO', ARRAY['https://statics.vinpearl.com/lang-nghe-o-ha-noi-11_1687856390.jpg', 'https://statics.vinpearl.com/lang-nghe-o-ha-noi-2_1687856175.jpg', 'https://tapchimoitruong.vn/uploads/092024/image001_31575948.jpg']::TEXT[], 'Trải nghiệm chợ và làng nghề Hà Nội bằng cách quan sát nghệ nhân, chọn sản vật, trò chuyện với người bán và cảm nhận nhịp sống mộc mạc của địa phương.', 'activity'),
('Du lịch sinh thái tại Hà Nội', 'HNO', ARRAY['https://bloganchoi.com/wp-content/uploads/2020/04/vuon-sinh-thai-ngoc-linh-khu-du-lich-sinh-thai-ua-thich-dip-cuoi-tuan-1.jpg', 'https://motogo.vn/wp-content/uploads/2023/10/khu-du-lich-sinh-thai-ha-noi-5.jpg', 'https://i0.wp.com/bloganchoi.com/wp-content/uploads/2020/04/vuon-sinh-thai-ngoc-linh-ha-noi.jpg']::TEXT[], 'Tham gia du lịch sinh thái tại Hà Nội với các hoạt động ngoài trời, không gian xanh, sông nước hoặc núi rừng, mang lại cảm giác thư giãn và gần gũi thiên nhiên.', 'activity'),
('Dạo phố đêm Hà Nội', 'HNO', ARRAY['https://cdnphoto.dantri.com.vn/GLdtSTqSPzKuLusZzBPENKyzR50=/thumb_w/1920/2024/11/01/halloween-hang-ma3-1730415670194.jpg', 'https://www.ciaonihon.com/wp-content/uploads/2024/12/1735266489_maxresdefault.jpg', 'https://lynntimes.com/lynntimesthanhthuy/wp-content/uploads/2024/04/du-lich-ha-noi-ve-dem-2.jpg']::TEXT[], 'Dạo phố đêm Hà Nội mang đến không khí rộn ràng của Hà Nội sau hoàng hôn, với ánh đèn, hàng quán, tiếng trò chuyện và nhịp sống đường phố đầy năng lượng.', 'entertainment'),
('Cà phê và ngắm cảnh Hà Nội', 'HNO', ARRAY['https://cafefcdn.com/203337114487263232/2022/9/9/photo-7-1662725361020131711789.jpg', 'http://campingsport.vn/wp-content/uploads/2024/11/Ca-phe-duong-tau-Ha-Noi-camping-sport-1-1024x536.jpg', 'https://datviettour.com.vn/uploads/images/tin-tuc-SEO/mien-bac/Ha-noi/danh-thang/Serein-Cafe.jpg']::TEXT[], 'Cà phê và ngắm cảnh Hà Nội gợi mở những không gian thư giãn tại Hà Nội, nơi du khách có thể nhâm nhi đồ uống, ngắm cảnh, trò chuyện và tận hưởng nhịp sống nhẹ nhàng.', 'entertainment'),
('Không gian ẩm thực tối Hà Nội', 'HNO', ARRAY['https://inhat.vn/wp-content/uploads/2020/08/nha-hang-khong-gian-dep-ha-noi-9.jpg', 'http://vuachaca.vn/wp-content/uploads/2016/02/62010550_895007520848620_163252613159059456_o.jpg', 'https://static.vinwonders.com/production/optimize_an-toi-ha-noi-9-722x451.jpg']::TEXT[], 'Không gian ẩm thực tối Hà Nội tạo nên trải nghiệm buổi tối sôi động ở Hà Nội, với quán ăn, món địa phương, hương thơm đường phố và bầu không khí tụ họp ấm cúng.', 'entertainment'),
('Trải nghiệm mua sắm Hà Nội', 'HNO', ARRAY['https://resource.kinhtedothi.vn/resources2025/1/users/41/1-1766658205.jpg', 'https://media-cdn-v2.laodong.vn/storage/newsportal/2023/11/10/1265630/Uniqlo-Van-Hoa-Viet--06.JPG', 'https://cdnmedia.baotintuc.vn/Upload/CCcQv1fjdlI5Hob1jh0mA/files/2025/12/26/TTDT2802.jpg']::TEXT[], 'Trải nghiệm mua sắm Hà Nội thể hiện nhịp sống thương mại của Hà Nội, từ chợ truyền thống đến cửa hàng hiện đại, nơi quà lưu niệm, đặc sản và dịch vụ mua sắm luôn nhộn nhịp.', 'entertainment'),
('Check-in cuối tuần tại Hà Nội', 'HNO', ARRAY['https://imgcdn.tapchicongthuong.vn/tcct-media/23/8/21/cuoi-tuan-check-in-voi-nhung-chiec-xe-hoa-o-con-duong-dep-nhat-ha-noi_64e2d123db32d.jpg', 'https://media-cdn-v2.laodong.vn/storage/newsportal/2022/9/24/1097076/Page.jpg?w=800&crop=auto&scale=both', 'https://statics.vinpearl.com/dia-diem-vui-choi-cuoi-tuan-o-ha-noi-1_1662306678.jpg']::TEXT[], 'Check-in cuối tuần tại Hà Nội là lựa chọn vui chơi nhẹ nhàng ở Hà Nội, phù hợp cho những buổi hẹn, chuyến đi ngắn, chụp ảnh kỷ niệm và tận hưởng không khí cuối tuần.', 'entertainment'),
('Biển Đồ Sơn', 'HPG', ARRAY['https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/10/do-son.jpg', 'https://sinhtour.vn/wp-content/uploads/2024/10/kinh-nghiem-du-lich-do-son.jpg', 'https://dulichkhampha24.com/wp-content/uploads/2023/02/bien-do-son-02-696x522.jpg']::TEXT[], 'Biển Đồ Sơn nổi bật với cảnh quan biển đảo đặc trưng của Hải Phòng, nơi mặt nước, bãi cát, núi đá hoặc làng chài tạo nên vẻ đẹp khoáng đạt và giàu sức hút.', 'landmarks'),
('Vịnh Lan Hạ', 'HPG', ARRAY['https://storage.googleapis.com/blogvxr-uploads/2025/05/70f25c30-vinh-lan-ha-hai-phong-5243444.jpg', 'https://focusasiatravel.vn/wp-content/uploads/2018/12/Vịnh-Lan-Hạ.jpg', 'https://storage.googleapis.com/blogvxr-uploads/2025/05/c768bdde-du-lich-vinh-lan-ha-hai-phong-8593603-661x450-1608297-6165173-8032643-4961984-8347383-3527394-2490325.jpeg']::TEXT[], 'Vịnh Lan Hạ nổi bật với cảnh quan biển đảo đặc trưng của Hải Phòng, nơi mặt nước, bãi cát, núi đá hoặc làng chài tạo nên vẻ đẹp khoáng đạt và giàu sức hút.', 'landmarks'),
('Cát Bà', 'HPG', ARRAY['https://statics.vinpearl.com/du-lich-cat-ba-hai-phong-1_1624253699.jpg', 'https://tinhaiphong.vn/wp-content/uploads/2020/12/4-Cat-Ba-Hai-Phong-co-gi-hay.jpg', 'https://catbaexpress.com/upload/images/Thi-Tran-Cat-Ba.jpg']::TEXT[], 'Cát Bà nổi bật với cảnh quan biển đảo đặc trưng của Hải Phòng, nơi mặt nước, bãi cát, núi đá hoặc làng chài tạo nên vẻ đẹp khoáng đạt và giàu sức hút.', 'landmarks'),
('Sông Bạch Đằng', 'HPG', ARRAY['https://statics.vinpearl.com/bach-dang-giang-9_1631618174.jpg', 'https://statics.vinpearl.com/bach-dang-giang-5_1631618001.jpg', 'https://statics.vinpearl.com/bach-dang-giang-thumb_1631618262.jpg']::TEXT[], 'Sông Bạch Đằng mang vẻ đẹp mặt nước đặc trưng của Hải Phòng, kết hợp không gian thoáng đãng, cảnh quan ven bờ và dấu ấn văn hóa gắn với đời sống địa phương.', 'landmarks'),
