('Thưởng thức đặc sản Hải Phòng', 'HPG', ARRAY['https://static.vinwonders.com/production/hai-san-hai-phong-banner.jpg', 'https://kenh14cdn.com/203336854389633024/2023/4/15/photo-6-1681531724762509486377.png', 'https://dulichkhatvongviet.com/wp-content/uploads/2014/07/dac_san_oc_hai_phong.jpg']::TEXT[], 'Thưởng thức đặc sản Hải Phòng qua những món ăn dân dã, hương vị địa phương và quán quen của người bản xứ, mang lại cảm giác gần gũi, no đủ và đáng nhớ trong hành trình.', 'activity'),
('Khám phá văn hóa địa phương Hải Phòng', 'HPG', ARRAY['http://sinhtour.vn/wp-content/uploads/2024/10/dia-diem-du-lich-hai-phong-5.jpg', 'https://namsontravel.com.vn/wp-content/uploads/2024/08/du-lich-bao-tang-hai-phong-scaled.jpg', 'https://ik.imagekit.io/tvlk/blog/2022/03/dia-diem-du-lich-hai-phong-5.jpg?tr=dpr-2,w-675']::TEXT[], 'Khám phá văn hóa Hải Phòng qua lễ hội, phong tục, kiến trúc, câu chuyện dân gian và đời sống cộng đồng, giúp du khách cảm nhận sâu hơn về con người và bản sắc địa phương.', 'activity'),
('Chụp ảnh cảnh đẹp Hải Phòng', 'HPG', ARRAY['https://cungphuot.info/wp-content/uploads/2014/06/kinh-nghiem-du-lich-cat-ba.jpg', 'https://cdn-media.sforum.vn/storage/app/media/thanhhuyen/ảnh+đẹp+hải+phòng/1/anh-dep-hai-phong-13.jpg', 'https://cdn-media.sforum.vn/storage/app/media/thanhhuyen/ảnh+đẹp+hải+phòng/anh-dep-hai-phong-56.jpg']::TEXT[], 'Chụp ảnh cảnh đẹp Hải Phòng qua những góc phố, dòng sông, ruộng đồng, núi rừng hoặc di tích nổi bật, lưu lại khoảnh khắc tự nhiên và cảm xúc riêng của chuyến đi.', 'activity'),
('Tham quan làng nghề và chợ địa phương Hải Phòng', 'HPG', ARRAY['https://ik.imagekit.io/tvlk/blog/2023/07/lang-may-tre-dan-phu-vinh-3-1024x683.png?tr=dpr-2,w-675', 'https://static.vinwonders.com/production/cho-hai-phong-1.jpg', 'https://statics.vinpearl.com/cho-hai-phong-07_1634113629.jpg']::TEXT[], 'Trải nghiệm chợ và làng nghề Hải Phòng bằng cách quan sát nghệ nhân, chọn sản vật, trò chuyện với người bán và cảm nhận nhịp sống mộc mạc của địa phương.', 'activity'),
('Du lịch sinh thái tại Hải Phòng', 'HPG', ARRAY['https://vhdn.vn/wp-content/uploads/2022/05/50-hangvemcatba.jpg', 'https://suckhoedoisong.qltns.mediacdn.vn/324455921873985536/2022/6/11/z348002381639838862a872a704a413a24b85639077af6-16549481776971349364634.jpg', 'https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/01_2024/khu_du_lich_sinh_thai_o_hai_phong_tien_lang_.jpg']::TEXT[], 'Tham gia du lịch sinh thái tại Hải Phòng với các hoạt động ngoài trời, không gian xanh, sông nước hoặc núi rừng, mang lại cảm giác thư giãn và gần gũi thiên nhiên.', 'activity'),
('Dạo phố đêm Hải Phòng', 'HPG', ARRAY['https://i.ytimg.com/vi/Af5pRNhFtDI/maxresdefault.jpg', 'https://i.ytimg.com/vi/tetl032PBWc/maxresdefault.jpg', 'https://i.vietgiaitri.com/2020/11/15/nhung-cay-cau-o-hai-phong-ve-dem-76e-5374705.jpg']::TEXT[], 'Dạo phố đêm Hải Phòng mang đến không khí rộn ràng của Hải Phòng sau hoàng hôn, với ánh đèn, hàng quán, tiếng trò chuyện và nhịp sống đường phố đầy năng lượng.', 'entertainment'),
