('Đền Mẫu Hưng Yên', 'HYE', ARRAY['https://lh6.googleusercontent.com/hsnx--DuMDmkIu5kve5mLga_5vbBXxnq-nbgio5bKQVQdikj7MwfSa-9_JdEfXehbamUx9DQQW72V77WHPfARaKOYXI9D6rz6Lrocuq7bBzcUxdCdPK19QbPPotYNgvlMLm_pJ6U', 'https://media-cdn-v2.laodong.vn/Storage/NewsPortal/2023/1/17/1139172/Z4047568736988_47D8f.jpg', 'https://vnn-imgs-f.vgcloud.vn/2020/08/14/22/bi-mat-trong-3-ngoi-den-chua-co-o-hung-yen.jpg']::TEXT[], 'Đền Mẫu Hưng Yên là công trình tâm linh và kiến trúc nổi bật của Hưng Yên, lưu giữ hoa văn, nếp thờ tự và nhiều giá trị văn hóa qua các thế hệ.', 'landmarks'),
('Chùa Chuông', 'HYE', ARRAY['https://static.vinwonders.com/production/chua-chuong-pho-hien-hung-yen.jpg', 'https://static.vinwonders.com/production/chua-chuong-hung-yen-banner.jpg', 'https://halotravel.vn/wp-content/uploads/2020/01/hung-yen-chua-nom-1-1024x678.jpg']::TEXT[], 'Chùa Chuông là công trình tâm linh và kiến trúc nổi bật của Hưng Yên, lưu giữ hoa văn, nếp thờ tự và nhiều giá trị văn hóa qua các thế hệ.', 'landmarks'),
('Làng Nôm', 'HYE', ARRAY['https://cdn3.ivivu.com/2022/12/làng-Nôm-Hưng-Yên-ivivu-1.jpg', 'https://cdn3.ivivu.com/2022/12/làng-Nôm-Hưng-Yên-ivivu.jpg', 'https://media.vietnamplus.vn/images/70ecbaf68ce60ced7af37d8bc1483e0f20d5223e83101aad40a36aa7be9e8c20710ddacc1295c0ec86c533c772177d9d/lang_Nom.jpg']::TEXT[], 'Làng Nôm phản ánh bản sắc đời sống của Hưng Yên, với kiến trúc, hàng quán, nghề truyền thống hoặc nhịp sinh hoạt cộng đồng giàu màu sắc địa phương.', 'landmarks'),
('Thưởng thức đặc sản Hưng Yên', 'HYE', ARRAY['https://ticotravel.com.vn/wp-content/uploads/2024/06/dac-san-Hung-Yen-5-768x571.jpg', 'https://www.vietnambooking.com/wp-content/uploads/2023/08/dac-san-hung-yen-12.jpg', 'https://static.vinwonders.com/production/dac-san-hung-yen-4-601x451.jpeg']::TEXT[], 'Thưởng thức đặc sản Hưng Yên qua những món ăn dân dã, hương vị địa phương và quán quen của người bản xứ, mang lại cảm giác gần gũi, no đủ và đáng nhớ trong hành trình.', 'activity'),
('Khám phá văn hóa địa phương Hưng Yên', 'HYE', ARRAY['https://ik.imagekit.io/tvlk/blog/2022/03/dia-diem-du-lich-hung-yen-1.jpg?tr=dpr-2,w-675', 'https://file.hstatic.net/200000684957/article/van-hoa-hung-yen_028fa76c79e04d06ae68a1a5997fe8c4.jpg', 'https://smartland.vn/wp-content/uploads/2024/12/duong-di-san-hung-yen4-768x504.jpg']::TEXT[], 'Khám phá văn hóa Hưng Yên qua lễ hội, phong tục, kiến trúc, câu chuyện dân gian và đời sống cộng đồng, giúp du khách cảm nhận sâu hơn về con người và bản sắc địa phương.', 'activity'),
('Chụp ảnh cảnh đẹp Hưng Yên', 'HYE', ARRAY['https://kinhnghiemdulich.gody.vn/wp-content/uploads/2022/06/dia-diem-du-lich-hung-yen-8.jpg', 'https://cdn.tgdd.vn/Files/2023/06/01/1532455/du-lich-hung-yen-voi-x-dia-diem-hap-dan-nhat-dinh-phai-ghe-202306011145441102.jpg', 'https://cdn-media.sforum.vn/storage/app/media/5v/danh-lam-thang-canh-hung-yen-thumb.jpg']::TEXT[], 'Chụp ảnh cảnh đẹp Hưng Yên qua những góc phố, dòng sông, ruộng đồng, núi rừng hoặc di tích nổi bật, lưu lại khoảnh khắc tự nhiên và cảm xúc riêng của chuyến đi.', 'activity'),
('Tham quan làng nghề và chợ địa phương Hưng Yên', 'HYE', ARRAY['https://file3.qdnd.vn/data/images/0/2023/05/11/phucthang/langthusyqdnd6.jpg?dpi=150&quality=100&w=870', 'https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/09_2022/lang-nghe-truyen-thong-o-hung-yen.jpg', 'https://dntt.mediacdn.vn/197608888129458176/2026/1/6/6120656611221579557008584573246299941960841862n-17676913905271501010767.jpg']::TEXT[], 'Trải nghiệm chợ và làng nghề Hưng Yên bằng cách quan sát nghệ nhân, chọn sản vật, trò chuyện với người bán và cảm nhận nhịp sống mộc mạc của địa phương.', 'activity'),
('Du lịch sinh thái tại Hưng Yên', 'HYE', ARRAY['https://hungyen.gov.vn/uploads/images/anhdep/nôm.jpg', 'https://static.vinwonders.com/production/chua-Phuc-Lam-hung-yen-5.jpg', 'https://static.vinwonders.com/production/chua-Phuc-Lam-hung-yen-1.jpg']::TEXT[], 'Tham gia du lịch sinh thái tại Hưng Yên với các hoạt động ngoài trời, không gian xanh, sông nước hoặc núi rừng, mang lại cảm giác thư giãn và gần gũi thiên nhiên.', 'activity'),
('Dạo phố đêm Hưng Yên', 'HYE', ARRAY['https://i.ytimg.com/vi/y-SnOmHK1tA/maxresdefault.jpg', 'https://i.ytimg.com/vi/TN7XRpkCpSY/maxresdefault.jpg', 'https://i.ytimg.com/vi/fSE9zZCU-iM/maxresdefault.jpg']::TEXT[], 'Dạo phố đêm Hưng Yên mang đến không khí rộn ràng của Hưng Yên sau hoàng hôn, với ánh đèn, hàng quán, tiếng trò chuyện và nhịp sống đường phố đầy năng lượng.', 'entertainment'),
('Cà phê và ngắm cảnh Hưng Yên', 'HYE', ARRAY['https://letsflytravel.vn/assets/source/me-linh-coffee-garden-2.jpg', 'https://happydaytravel.com/wp-content/uploads/2020/06/2-compressed.jpg', 'https://cdn.eva.vn/upload/3-2024/images/lienntt1/picture-458977551-1723730635-631-width1536height2048.jpg']::TEXT[], 'Cà phê và ngắm cảnh Hưng Yên gợi mở những không gian thư giãn tại Hưng Yên, nơi du khách có thể nhâm nhi đồ uống, ngắm cảnh, trò chuyện và tận hưởng nhịp sống nhẹ nhàng.', 'entertainment'),
('Không gian ẩm thực tối Hưng Yên', 'HYE', ARRAY['https://vuadesign.com.vn/wp-content/uploads/2024/11/313930126365005.612c66ed1a261-1.jpg', 'https://photo.znews.vn/Uploaded/wyhktpu/2025_11_28/thumb.jpg', 'https://dulichvn.net/wp-content/uploads/2024/11/Anh-chup-man-hinh-2024-11-08-153526-709x800.jpg']::TEXT[], 'Không gian ẩm thực tối Hưng Yên tạo nên trải nghiệm buổi tối sôi động ở Hưng Yên, với quán ăn, món địa phương, hương thơm đường phố và bầu không khí tụ họp ấm cúng.', 'entertainment'),
('Trải nghiệm mua sắm Hưng Yên', 'HYE', ARRAY['https://photo.znews.vn/Uploaded/wyhktpu/2025_10_05/Anh_1.JPG', 'https://mekongasean.vn/stores/news_dataimages/2025/062025/07/12/3120250607125140.jpg?rt=20250607125246', 'https://mekongasean.vn/stores/news_dataimages/2025/112025/19/12/11720251119125251.jpg?rt=20251119130121']::TEXT[], 'Trải nghiệm mua sắm Hưng Yên thể hiện nhịp sống thương mại của Hưng Yên, từ chợ truyền thống đến cửa hàng hiện đại, nơi quà lưu niệm, đặc sản và dịch vụ mua sắm luôn nhộn nhịp.', 'entertainment'),
('Check-in cuối tuần tại Hưng Yên', 'HYE', ARRAY['https://khamphadisan.com.vn/wp-content/uploads/2023/04/lang-nom-khamphadisan.png', 'https://static.vinwonders.com/production/chua-Phuc-Lam-hung-yen-5.jpg', 'https://static.vinwonders.com/production/chua-Phuc-Lam-hung-yen-1.jpg']::TEXT[], 'Check-in cuối tuần tại Hưng Yên là lựa chọn vui chơi nhẹ nhàng ở Hưng Yên, phù hợp cho những buổi hẹn, chuyến đi ngắn, chụp ảnh kỷ niệm và tận hưởng không khí cuối tuần.', 'entertainment'),
('Tràng An', 'NBI', ARRAY['https://hanoibylocals.com/wp-content/uploads/2024/02/trang-an-ninh-binh-1.jpg', 'https://onevivu.vn/wp-content/uploads/2020/10/Du-lich-Trang-An-Ninh-Binh-5.jpg', 'https://hanoiexploretravel.com/wp-content/uploads/2025/01/trang-an-ninh-binh6.jpeg']::TEXT[], 'Tràng An là địa danh tiêu biểu của Ninh Bình, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Tam Cốc - Bích Động', 'NBI', ARRAY['https://media.gody.vn/images/ninh-binh/tam-coc-bich-dong/12-2016/20161213092350-tam-coc-bich-dong-gody+(19).jpg', 'http://dulichdenachau.com/userfiles/images/tam-coc-bich-dong-ninh-binh.jpg', 'https://ohdidi.vn/uploads/static/NEWS/blog/tam+coc+ninh+binh/tam_coc_ninh_binh_5.png']::TEXT[], 'Tam Cốc - Bích Động là địa danh tiêu biểu của Ninh Bình, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Cố đô Hoa Lư', 'NBI', ARRAY['https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2017/07/khu-du-lich-co-do-hoa-lu.jpg', 'https://datviettour.com.vn/uploads/images/tin-tuc-SEO/mien-bac/Ninh-Binh/danh-thang/co-do-hoa-lu-2.jpg', 'https://datviettour.com.vn/uploads/images/tin-tuc-SEO/mien-bac/Ninh-Binh/danh-thang/hoa-lu.jpg']::TEXT[], 'Cố đô Hoa Lư ghi dấu những lớp lịch sử quan trọng của Ninh Bình, với không gian trưng bày, kiến trúc hoặc dấu tích giúp tái hiện ký ức văn hóa địa phương.', 'landmarks'),
('Chùa Bái Đính', 'NBI', ARRAY['https://booking.pystravel.vn/uploads/posts/albums/8/9456fe40364d9167df75ae7b1c785753.jpg', 'https://denbachuakho.com.vn/wp-content/uploads/2022/06/chua-bai-dinh-ninh-binh-2-1-scaled.jpg', 'https://ticotravel.com.vn/wp-content/uploads/2022/05/Chua-Bai-Dinh-Ninh-Binh-10.jpg']::TEXT[], 'Chùa Bái Đính là công trình tâm linh và kiến trúc nổi bật của Ninh Bình, lưu giữ hoa văn, nếp thờ tự và nhiều giá trị văn hóa qua các thế hệ.', 'landmarks'),
('Hang Múa', 'NBI', ARRAY['https://static.vecteezy.com/system/resources/previews/057/799/208/large_2x/aerial-view-of-hang-mua-viewpoint-and-picturesque-landscape-of-ninh-binh-vietnam-photo.jpg', 'https://luxtour.com.vn/wp-content/uploads/2022/12/hang-mua-ninh-binh-3.png', 'https://phuotvivu.com/blog/wp-content/uploads/2019/02/hang-mua-ninh-binh-2.jpg']::TEXT[], 'Hang Múa nổi bật với cảnh quan thiên nhiên của Ninh Bình, nơi địa hình núi rừng, thác nước, hang động hoặc tầng mây tạo nên vẻ đẹp hùng vĩ và nguyên sơ.', 'landmarks'),
