('Dạo phố đêm Đà Nẵng', 'DNG', ARRAY['https://cdn3.ivivu.com/2015/01/tour-tet-da-nang-ivivu.com-14.jpg', 'https://hungphatres.vn/wp-content/uploads/2025/03/pho-ve-dem.jpg', 'https://truongsatour.com/uploads/images/pho-di-bo-bach-dang.jpg']::TEXT[], 'Dạo phố đêm Đà Nẵng mang đến không khí rộn ràng của Đà Nẵng sau hoàng hôn, với ánh đèn, hàng quán, tiếng trò chuyện và nhịp sống đường phố đầy năng lượng.', 'entertainment'),
('Cà phê và ngắm cảnh Đà Nẵng', 'DNG', ARRAY['https://cdn.justfly.vn/2048x1536/media/202303/14/1678762837-quan-ca-phe-hon-da-thuyen-da-nang.jpg', 'https://danang.coffee/wp-content/uploads/2025/08/di-ca-phe-cover.jpg', 'https://danangfantasticity.com/wp-content/uploads/2025/04/ca-phe-trung-3t-do-bo-da-nang-01.jpg']::TEXT[], 'Cà phê và ngắm cảnh Đà Nẵng gợi mở những không gian thư giãn tại Đà Nẵng, nơi du khách có thể nhâm nhi đồ uống, ngắm cảnh, trò chuyện và tận hưởng nhịp sống nhẹ nhàng.', 'entertainment'),
('Không gian ẩm thực tối Đà Nẵng', 'DNG', ARRAY['https://bepnhatoi.net/wp-content/uploads/2025/06/mo-ta-tong-the-khong-gian-nha-hang-hai-san-ngoc-huong-da-nang.webp', 'https://danangfantasticity.com/wp-content/uploads/2025/08/spice-viet-hoi-an-khong-gian-am-thuc-dac-sac-giua-long-pho-co-04.jpg', 'https://ghiendanang.com/wp-content/uploads/2025/02/nha-hang-hue-xua-da-nang-2.jpg']::TEXT[], 'Không gian ẩm thực tối Đà Nẵng tạo nên trải nghiệm buổi tối sôi động ở Đà Nẵng, với quán ăn, món địa phương, hương thơm đường phố và bầu không khí tụ họp ấm cúng.', 'entertainment'),
('Trải nghiệm mua sắm Đà Nẵng', 'DNG', ARRAY['https://www.robins.vn/wp-content/uploads/2025/07/lotte-6.jpg.jpg', 'https://media.vietravel.com/images/Content/dia-diem-mua-sam-o-da-nang-2.jpg', 'https://danang.digital/wp-content/uploads/2025/02/cho-han-da-nang-2.jpg']::TEXT[], 'Trải nghiệm mua sắm Đà Nẵng thể hiện nhịp sống thương mại của Đà Nẵng, từ chợ truyền thống đến cửa hàng hiện đại, nơi quà lưu niệm, đặc sản và dịch vụ mua sắm luôn nhộn nhịp.', 'entertainment'),
('Check-in cuối tuần tại Đà Nẵng', 'DNG', ARRAY['https://www.cotrang.org/public/images/tin_dang/9/71_hai-van-xanh-glamping-da-nang-bk-28.jpg', 'https://file.hstatic.net/200000504041/file/cau-tinh-yeu-da-nang_e16162ff92ba424694a79f6cfdcd2412_grande.jpg', 'https://checkindanang.vn/wp-content/uploads/2022/03/hai-van-garden-dia-diem-check-in-moi-noi-sieu-tho-mong-rat-duoc-long-gioi-tre-8-3.jpg']::TEXT[], 'Check-in cuối tuần tại Đà Nẵng là lựa chọn vui chơi nhẹ nhàng ở Đà Nẵng, phù hợp cho những buổi hẹn, chuyến đi ngắn, chụp ảnh kỷ niệm và tận hưởng không khí cuối tuần.', 'entertainment'),
('Nhà dài Ê Đê', 'DLA', ARRAY['https://images.baodantoc.vn/uploads/2023/Tháng+4/Ngày_18/NGÂN/Ảnh+1+(2)+sua.jpg', 'https://www.daklak.city/uploads/files/2019/08/23/thumbs-1200-628-2--1/van-hoa-nha-dai-cua-nguoi-e-de-dak-lak-1.JPG', 'https://cly.1cdn.vn/2025/02/05/398-202502051619491.png']::TEXT[], 'Nhà dài Ê Đê là địa danh tiêu biểu của Đắk Lắk, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Buôn Đôn', 'DLA', ARRAY['https://cdn.tgdd.vn/Files/2023/09/28/1549550/du-lich-buon-don-dak-lak-7-dia-diem-khong-the-bo-lo-202309282148183242.jpg', 'https://image.vietgoing.com/editor/image_nps1644372708.jpg', 'https://bizweb.dktcdn.net/100/149/137/articles/2-buon-don-thaiantravel.jpg?v=1668919205413']::TEXT[], 'Buôn Đôn phản ánh bản sắc đời sống của Đắk Lắk, với kiến trúc, hàng quán, nghề truyền thống hoặc nhịp sinh hoạt cộng đồng giàu màu sắc địa phương.', 'landmarks'),
('Hồ Lắk', 'DLA', ARRAY['https://cdn3.ivivu.com/2022/10/hồ-lak-ivivu-5.jpg', 'https://nhanghitaynguyen.com/wp-content/uploads/2020/09/tham-quan-ho-lak.jpg', 'https://media.gody.vn/images/dak-lak/ho-lak/10-2016/20161031070216-ho-lak-gody(4).jpg']::TEXT[], 'Hồ Lắk mang vẻ đẹp mặt nước đặc trưng của Đắk Lắk, kết hợp không gian thoáng đãng, cảnh quan ven bờ và dấu ấn văn hóa gắn với đời sống địa phương.', 'landmarks'),
('Thác Dray Nur', 'DLA', ARRAY['https://taynguyen.travel/wp-content/uploads/2020/02/CNDL_VN_TN_Thac-Dray-Nur_transviet_the_wandering_lantern-768x576.jpg', 'https://tripmap.vn/wp-content/uploads/2021/07/thac-dray-nur-1627268728357.jpg', 'https://gotour.com.vn/wp-content/uploads/2019/08/Thac-Dray-Nur-Dak-Lak.jpg']::TEXT[], 'Thác Dray Nur nổi bật với cảnh quan thiên nhiên của Đắk Lắk, nơi địa hình núi rừng, thác nước, hang động hoặc tầng mây tạo nên vẻ đẹp hùng vĩ và nguyên sơ.', 'landmarks'),
('Bảo tàng Thế giới Cà phê', 'DLA', ARRAY['https://hotel84.com/userfiles/image/dulich/dakLak/bao-tang-the-gioi-caphe-toa.jpg', 'https://media.vov.vn/sites/default/files/styles/large_watermark/public/2021-04/bao_tang_tgcf_20.jpg', 'https://cdn3.ivivu.com/2019/09/bao-tang-ca-phe-o-buon-ma-thuot-ivivu-2.jpg']::TEXT[], 'Bảo tàng Thế giới Cà phê ghi dấu những lớp lịch sử quan trọng của Đắk Lắk, với không gian trưng bày, kiến trúc hoặc dấu tích giúp tái hiện ký ức văn hóa địa phương.', 'landmarks'),
('Thưởng thức đặc sản Đắk Lắk', 'DLA', ARRAY['https://ticotravel.com.vn/wp-content/uploads/2022/08/Dac-san-Dak-Lak-1.jpg', 'https://poliva.vn/wp-content/uploads/2019/08/lau-ca-lang1.jpg', 'https://q.vietgiaitri.com/2024/9/17/bun-chia-dac-san-dak-lak-mon-an-dang-de-ban-thuong-thuc-trong-doi-va-tu-tay-lam-tai-nha-76d5e-7269748_default.webp']::TEXT[], 'Thưởng thức đặc sản Đắk Lắk qua những món ăn dân dã, hương vị địa phương và quán quen của người bản xứ, mang lại cảm giác gần gũi, no đủ và đáng nhớ trong hành trình.', 'activity'),
('Khám phá văn hóa địa phương Đắk Lắk', 'DLA', ARRAY['https://bvhttdl.mediacdn.vn/291773308735864832/2024/9/20/2009dak-lak-van-hoa-truyen-thong-3-1726802622107-17268026224231095457512.jpg', 'https://images.vietnamtourism.gov.vn/vn/images/2024/thang_9/2009.dak-lak-van-hoa-truyen-thong-1.jpg', 'https://thuonghieudoisong.vn/wp-content/uploads/2025/11/z7225649259307_dbc3a6b1b40d32b6535176b391621bed.jpg']::TEXT[], 'Khám phá văn hóa Đắk Lắk qua lễ hội, phong tục, kiến trúc, câu chuyện dân gian và đời sống cộng đồng, giúp du khách cảm nhận sâu hơn về con người và bản sắc địa phương.', 'activity'),
('Chụp ảnh cảnh đẹp Đắk Lắk', 'DLA', ARRAY['https://images.baodantoc.vn/uploads/2021/Tháng_10/Ngày_14/NGNÂ/thác+Dray+Nur/45-1634114959-draynu.jpg', 'https://toplist.vn/images/800px/thac-dray-nur-422704.jpg', 'https://kinhnghiemdulich.gody.vn/wp-content/uploads/2021/12/dia-diem-du-lich-dak-lak-8.jpg']::TEXT[], 'Chụp ảnh cảnh đẹp Đắk Lắk qua những góc phố, dòng sông, ruộng đồng, núi rừng hoặc di tích nổi bật, lưu lại khoảnh khắc tự nhiên và cảm xúc riêng của chuyến đi.', 'activity'),
