('Thung lũng Tình Yêu', 'LDG', ARRAY['https://cafefcdn.com/thumb_w/640/203337114487263232/2021/12/30/photo1640855700570-16408557006811641069905.jpg', 'https://dulichcaonguyen.com/wp-content/uploads/2025/05/Thung-lung-tinh-yeu-Da-Lat-1_23022024102445-760x380.jpg', 'https://bap360.com/wp-content/uploads/2025/05/Thung-Lung-Tinh-Yeu.png']::TEXT[], 'Thung lũng Tình Yêu là địa danh tiêu biểu của Lâm Đồng, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Thác Datanla', 'LDG', ARRAY['https://tourdulichgiare.com.vn/wp-content/uploads/2023/08/canh-dep-cua-thac-datanla.jpg', 'https://storage.googleapis.com/blogvxr-uploads/2025/04/de3c4aec-thac-datanla-5276937-600x450-5950399-9114658-1765867.jpg', 'https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhbcO6PnLtT4qN8TwMG4TC521WNQXZ3WALVChfMzkIx7QV_AFjKh6yKqg2AKVpeA2EH4e3_0EQOyj718Tw1aNSmuhUYrEGXG34rhyphenhyphen6csJNA_01tSDmdncjAEGVtCaELO0eDo2lsb2Fkz30/s1600/da+lat-+thac+datanla.jpg']::TEXT[], 'Thác Datanla nổi bật với cảnh quan thiên nhiên của Lâm Đồng, nơi địa hình núi rừng, thác nước, hang động hoặc tầng mây tạo nên vẻ đẹp hùng vĩ và nguyên sơ.', 'landmarks'),
('Đồi chè Cầu Đất', 'LDG', ARRAY['https://media.gody.vn/images/lam-dong/doi-che-cau-dat/1-2017/20170104091915-doi-che-cau-dat-gody+(5).jpg', 'https://static.vinwonders.com/production/doi-che-cau-dat.jpg', 'https://i.ytimg.com/vi/oIvwMGZaZ_4/maxresdefault.jpg']::TEXT[], 'Đồi chè Cầu Đất nổi bật với cảnh quan thiên nhiên của Lâm Đồng, nơi địa hình núi rừng, thác nước, hang động hoặc tầng mây tạo nên vẻ đẹp hùng vĩ và nguyên sơ.', 'landmarks'),
('Ga Đà Lạt', 'LDG', ARRAY['https://cdn.tcdulichtphcm.vn/upload/3-2024/images/2024-07-11/1720702844-rsz_lam-dong.jpeg', 'https://cdnmedia.baotintuc.vn/Upload/e9GdNZvHDFi8lZSWc6ubA/files/2024/07/ga-da-lat-11724-2.jpg', 'https://cdn.tcdulichtphcm.vn/upload/3-2024/images/2024-07-11/1720703321-thumbnail-width1200height628-watermark.jpg']::TEXT[], 'Ga Đà Lạt là địa danh tiêu biểu của Lâm Đồng, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Thưởng thức đặc sản Lâm Đồng', 'LDG', ARRAY['https://dobuon.vn/wp-content/uploads/2024/09/dac-san-lam-dong-11.jpg', 'https://dobuon.vn/wp-content/uploads/2024/09/dac-san-lam-dong-7.jpg', 'https://cdn.tgdd.vn/Files/2022/06/27/1442859/lam-dong-co-dac-san-gi-15-dac-san-lam-dong-mua-lam-qua-202206270839458702.jpg']::TEXT[], 'Thưởng thức đặc sản Lâm Đồng qua những món ăn dân dã, hương vị địa phương và quán quen của người bản xứ, mang lại cảm giác gần gũi, no đủ và đáng nhớ trong hành trình.', 'activity'),
('Khám phá văn hóa địa phương Lâm Đồng', 'LDG', ARRAY['https://media.vietravel.com/images/news/dia-diem-du-lich-van-hoa-lam-dong.png', 'https://mia.vn/media/uploads/blog-du-lich/bao-tang-lam-dong-02-1703295922.jpeg', 'https://hoadalattravel.vn/wp-content/uploads/2024/10/lam-dong.jpeg']::TEXT[], 'Khám phá văn hóa Lâm Đồng qua lễ hội, phong tục, kiến trúc, câu chuyện dân gian và đời sống cộng đồng, giúp du khách cảm nhận sâu hơn về con người và bản sắc địa phương.', 'activity'),
('Chụp ảnh cảnh đẹp Lâm Đồng', 'LDG', ARRAY['https://cdn-media.sforum.vn/storage/app/media/ctvseo_MH/ảnh+đẹp+lâm+đồng/anh-dep-lam-dong-39.jpg', 'https://cdn.tgdd.vn/Files/2023/10/25/1553008/top-22-dia-diem-du-lich-lam-dong-dep-nhat-dinh-khong-nen-bo-qua-202310251510051130.jpg', 'https://checkinvietnam.vtc.vn/media/20220311/images/thao-nguyen-dong-lam-1.jpg']::TEXT[], 'Chụp ảnh cảnh đẹp Lâm Đồng qua những góc phố, dòng sông, ruộng đồng, núi rừng hoặc di tích nổi bật, lưu lại khoảnh khắc tự nhiên và cảm xúc riêng của chuyến đi.', 'activity'),
('Tham quan làng nghề và chợ địa phương Lâm Đồng', 'LDG', ARRAY['https://ik.imagekit.io/tvlk/blog/2023/07/lang-may-tre-dan-phu-vinh-3-1024x683.png?tr=dpr-2,w-675', 'https://images.baodantoc.vn/thumbs/600x315/uploads/2025/Thang-10/Ngay-10/Anh/1/z7101478046913-e6e20cd021c5521485a532f6e1123e3f20251010130358-1.jpg', 'https://moit.gov.vn/upload/2005517/fck/files/z5895155778670_d6c29955f5881fc42db9b1ee8cf73a85_f56b8.jpg']::TEXT[], 'Trải nghiệm chợ và làng nghề Lâm Đồng bằng cách quan sát nghệ nhân, chọn sản vật, trò chuyện với người bán và cảm nhận nhịp sống mộc mạc của địa phương.', 'activity'),
('Du lịch sinh thái tại Lâm Đồng', 'LDG', ARRAY['https://2.bp.blogspot.com/-LYsdu12nYbQ/U0-riKTL4EI/AAAAAAAAD-w/lv2eDWpxSrE/s1600/khu-du-lịch-sinh-thai-rung-Madagui-di-du-lich-Da-Lat-4.jpg', 'https://data1.8trip.vn/newsTravellink/content/files/239809609_189879983209530_2824021186795174610_n.jpg', 'https://media.vneconomy.vn/w800/images/upload/2023/03/28/du-lich.jpg']::TEXT[], 'Tham gia du lịch sinh thái tại Lâm Đồng với các hoạt động ngoài trời, không gian xanh, sông nước hoặc núi rừng, mang lại cảm giác thư giãn và gần gũi thiên nhiên.', 'activity'),
('Dạo phố đêm Lâm Đồng', 'LDG', ARRAY['https://cdn.tgdd.vn/Files/2023/10/25/1553008/top-22-dia-diem-du-lich-lam-dong-dep-nhat-dinh-khong-nen-bo-qua-202310251510051130.jpg', 'https://images.vietnamtourism.gov.vn/vn/images/2025/thang_9/1209.lamdong.jpg', 'https://khangdiensaigon.com.vn/wp-content/uploads/2021/02/thanh-pho-bao-loc-lam-dong.jpg']::TEXT[], 'Dạo phố đêm Lâm Đồng mang đến không khí rộn ràng của Lâm Đồng sau hoàng hôn, với ánh đèn, hàng quán, tiếng trò chuyện và nhịp sống đường phố đầy năng lượng.', 'entertainment'),
('Cà phê và ngắm cảnh Lâm Đồng', 'LDG', ARRAY['https://photo-baomoi.bmcdn.me/w700_r1/2025_02_23_465_51547495/9aef5ec875869cd8c597.jpg', 'https://vov.vn/sites/default/files/styles/large_watermark/public/2024-12/5_12_gia_ca_phe_1_20241204212549.jpg', 'https://photo-baomoi.bmcdn.me/w700_r1/2025_02_23_465_51547495/3e0efe29d5673c396576.jpg']::TEXT[], 'Cà phê và ngắm cảnh Lâm Đồng gợi mở những không gian thư giãn tại Lâm Đồng, nơi du khách có thể nhâm nhi đồ uống, ngắm cảnh, trò chuyện và tận hưởng nhịp sống nhẹ nhàng.', 'entertainment'),
('Không gian ẩm thực tối Lâm Đồng', 'LDG', ARRAY['https://denmaytre.net/wp-content/uploads/2023/09/trang-tri-quan-an-bang-tre-15.png', 'https://cdn.tuoitre.vn/471584752817336320/2024/6/1/base64-1717254782090538010821.jpeg', 'https://lamdongtropicalvillas.com/wp-content/uploads/2024/12/am-thuc-2048x1365.jpg']::TEXT[], 'Không gian ẩm thực tối Lâm Đồng tạo nên trải nghiệm buổi tối sôi động ở Lâm Đồng, với quán ăn, món địa phương, hương thơm đường phố và bầu không khí tụ họp ấm cúng.', 'entertainment'),
('Trải nghiệm mua sắm Lâm Đồng', 'LDG', ARRAY['https://media-cdn-v2.laodong.vn/storage/newsportal/2025/5/6/1502374/Dl.jpg', 'https://daknong.1cdn.vn/2025/10/26/cac-san-pham-ocop-lam-dong.jpg', 'https://hungphatsaigon.vn/wp-content/uploads/2024/11/cua-hang-sofa-lam-dong.jpg']::TEXT[], 'Trải nghiệm mua sắm Lâm Đồng thể hiện nhịp sống thương mại của Lâm Đồng, từ chợ truyền thống đến cửa hàng hiện đại, nơi quà lưu niệm, đặc sản và dịch vụ mua sắm luôn nhộn nhịp.', 'entertainment'),
('Check-in cuối tuần tại Lâm Đồng', 'LDG', ARRAY['https://riviuhay.net/wp-content/uploads/2024/05/Untitled-3-2.jpg', 'https://cdn-media.sforum.vn/storage/app/media/ctvseo_MH/ảnh+đẹp+lâm+đồng/anh-dep-lam-dong-48.jpg', 'https://riviuhay.net/wp-content/uploads/2024/06/Untitled-1-52.jpg']::TEXT[], 'Check-in cuối tuần tại Lâm Đồng là lựa chọn vui chơi nhẹ nhàng ở Lâm Đồng, phù hợp cho những buổi hẹn, chuyến đi ngắn, chụp ảnh kỷ niệm và tận hưởng không khí cuối tuần.', 'entertainment'),
('Đảo Lý Sơn', 'QNG', ARRAY['https://statics.vinpearl.com/huyen-dao-ly-son_1742399346.jpg', 'https://media.techcity.cloud/vietnam.vn/2023/05/anh-2-ly-son-1683692364174.jpg', 'https://bvhttdl.mediacdn.vn/291773308735864832/2024/7/2/anh-18-giai-boi-vuot-bien-ly-son-gui-tap-chi-1719886170-812-width1379height698-1719904832134-1719904832590778623877.jpg']::TEXT[], 'Đảo Lý Sơn nổi bật với cảnh quan biển đảo đặc trưng của Quảng Ngãi, nơi mặt nước, bãi cát, núi đá hoặc làng chài tạo nên vẻ đẹp khoáng đạt và giàu sức hút.', 'landmarks'),
