('Hòn Khoai', 'CMU', ARRAY['https://cdn.tgdd.vn/Files/2022/07/20/1449308/kinh-nghiem-du-lich-dao-hon-khoai-ca-mau-tu-a-z-cho-chuyen-di-tron-ven-202207201725158830.jpg', 'https://datmuixanh.com/wp-content/uploads/2021/08/dao-hon-khoai-ca-mau-02.jpg', 'https://thamhiemmekong.com/wp-content/uploads/2020/04/honkhoai.jpg']::TEXT[], 'Hòn Khoai là địa danh tiêu biểu của Cà Mau, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Hòn Chuối', 'CMU', ARRAY['https://thamhiemmekong.com/wp-content/uploads/2020/06/honchuoi3.jpg', 'https://cdn3.ivivu.com/2023/03/hchuoi.jpg', 'https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/02_2023/dao-hon-chuoi-ca-mau-hai.jpg']::TEXT[], 'Hòn Chuối là địa danh tiêu biểu của Cà Mau, nổi bật bởi cảnh quan, kiến trúc hoặc chiều sâu văn hóa, góp phần tạo nên bản sắc du lịch riêng của địa phương.', 'landmarks'),
('Rừng ngập mặn Cà Mau', 'CMU', ARRAY['https://cdnv2.tgdd.vn/bhx-static/bhx/News/Images/2024/09/30/1570598/hinh-bai-tin-bhx-62_202409301643161978.jpg', 'https://image.vietgoing.com/destination/vietgoing_bgi2103251979.webp', 'https://media.mia.vn/uploads/blog-du-lich/kham-pha-rung-ngap-man-ca-mau-voi-vo-van-trai-nghiem-thu-vi-08-1662985773.jpeg']::TEXT[], 'Rừng ngập mặn Cà Mau nổi bật với cảnh quan thiên nhiên của Cà Mau, nơi địa hình núi rừng, thác nước, hang động hoặc tầng mây tạo nên vẻ đẹp hùng vĩ và nguyên sơ.', 'landmarks'),
('Thưởng thức đặc sản Cà Mau', 'CMU', ARRAY['https://dacsanthanhnam.com/wp-content/uploads/2022/06/dac-san-ca-mau.jpg', 'https://r2.nucuoimekong.com/wp-content/uploads/dac-san-ca-mau-cua-ca-mau.jpg', 'https://ik.imagekit.io/tvlk/blog/2022/09/dac-san-ca-mau-2-1024x769.jpg?tr=dpr-2,w-675']::TEXT[], 'Thưởng thức đặc sản Cà Mau qua những món ăn dân dã, hương vị địa phương và quán quen của người bản xứ, mang lại cảm giác gần gũi, no đủ và đáng nhớ trong hành trình.', 'activity'),
('Khám phá văn hóa địa phương Cà Mau', 'CMU', ARRAY['https://camaueco.com/wp-content/uploads/2023/08/khu-du-lich-sinh-thai-ca-mau-1-768x512.jpg', 'https://hoangaulactourist.com/upload/images/2.jpg', 'https://booking.muongthanh.com/upload_images/images/H`/cong-vien-van-hoa-mui-ca-mau.jpg']::TEXT[], 'Khám phá văn hóa Cà Mau qua lễ hội, phong tục, kiến trúc, câu chuyện dân gian và đời sống cộng đồng, giúp du khách cảm nhận sâu hơn về con người và bản sắc địa phương.', 'activity'),
('Chụp ảnh cảnh đẹp Cà Mau', 'CMU', ARRAY['https://cdn-media.sforum.vn/storage/app/media/ctvseo_MH/ảnh+đẹp+cà+mau/anh-dep-ca-mau-38.jpg', 'http://cdn.tgdd.vn/Files/2022/03/25/1422292/du-lich-hon-da-bac-kham-pha-ve-dep-chon-tien-canh-ca-mau-202203250800412645.jpg', 'https://baocamau.vn/image/ckeditor/2023/20231012/images/4.jpg']::TEXT[], 'Chụp ảnh cảnh đẹp Cà Mau qua những góc phố, dòng sông, ruộng đồng, núi rừng hoặc di tích nổi bật, lưu lại khoảnh khắc tự nhiên và cảm xúc riêng của chuyến đi.', 'activity'),
('Tham quan làng nghề và chợ địa phương Cà Mau', 'CMU', ARRAY['https://ik.imagekit.io/tvlk/blog/2022/03/dia-diem-du-lich-ca-mau-4.jpg?tr=dpr-2,w-675', 'https://cdn.vntrip.vn/cam-nang/wp-content/uploads/2018/09/cho-noi-ca-mau-vntrip6-1.jpg', 'https://bazaarvietnam.vn/wp-content/uploads/2025/05/harper-bazaar-du-lich-ca-mau-3.jpg']::TEXT[], 'Trải nghiệm chợ và làng nghề Cà Mau bằng cách quan sát nghệ nhân, chọn sản vật, trò chuyện với người bán và cảm nhận nhịp sống mộc mạc của địa phương.', 'activity'),
('Du lịch sinh thái tại Cà Mau', 'CMU', ARRAY['https://cdnmedia.baotintuc.vn/Upload/DmtgOUlHWBO5POIHzIwr1A/files/2024/10/23/dlst-mui-ca-mau-23102024-04.jpg', 'https://camaueco.com/wp-content/uploads/2023/09/khu-du-lich-sinh-thai-ca-mau-nen-den-2-scaled.jpg', 'https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/07_2024/khu_du_lich_sinh_thai_ca_mau_eco.jpg']::TEXT[], 'Tham gia du lịch sinh thái tại Cà Mau với các hoạt động ngoài trời, không gian xanh, sông nước hoặc núi rừng, mang lại cảm giác thư giãn và gần gũi thiên nhiên.', 'activity'),
('Dạo phố đêm Cà Mau', 'CMU', ARRAY['https://ongvove.com/uploads/0000/17/2023/12/14/cho-dem-ca-mau.jpg', 'https://dulich9.com/wp-content/uploads/2016/11/du-lich-Ca-Mau-1-ngay-5.jpg', 'https://cdn.media.dulich24.com.vn/diemden/ca-mau-6645/0f1ebd68-678c-4296-9cd0-8328f731fed2-28.jpg']::TEXT[], 'Dạo phố đêm Cà Mau mang đến không khí rộn ràng của Cà Mau sau hoàng hôn, với ánh đèn, hàng quán, tiếng trò chuyện và nhịp sống đường phố đầy năng lượng.', 'entertainment'),
('Cà phê và ngắm cảnh Cà Mau', 'CMU', ARRAY['https://letsflytravel.vn/assets/source/me-linh-coffee-garden-2.jpg', 'https://bepnhatoi.net/wp-content/uploads/2025/06/thuong-thuc-ca-phe-va-ngam-canh-tai-up-cafe.webp', 'https://www.lethuytravel.com/uploaded/Anh-Cam-Nang/cn-dl-tamdao/tiemcaphenhietdoitamdao.jpg']::TEXT[], 'Cà phê và ngắm cảnh Cà Mau gợi mở những không gian thư giãn tại Cà Mau, nơi du khách có thể nhâm nhi đồ uống, ngắm cảnh, trò chuyện và tận hưởng nhịp sống nhẹ nhàng.', 'entertainment'),
('Không gian ẩm thực tối Cà Mau', 'CMU', ARRAY['https://media.mia.vn/uploads/blog-du-lich/ghe-quan-mi-cay-yagami-ca-mau-thuong-thuc-am-thuc-da-quoc-gia-7-1663650759.jpg', 'https://images2.thanhnien.vn/528068263637045248/2025/11/18/img4742-1763437001553880606637.jpg', 'https://static-images.vnncdn.net/vps_images_publish/000001/000003/2025/11/18/w-le-hoi-19jpg-3831.jpg']::TEXT[], 'Không gian ẩm thực tối Cà Mau tạo nên trải nghiệm buổi tối sôi động ở Cà Mau, với quán ăn, món địa phương, hương thơm đường phố và bầu không khí tụ họp ấm cúng.', 'entertainment'),
('Trải nghiệm mua sắm Cà Mau', 'CMU', ARRAY['https://images2.thanhnien.vn/528068263637045248/2024/7/29/h3-17222387278511030776576.png', 'https://crescent.com.vn/wp-content/uploads/2025/04/vi-tri-jollibee-trong-sense-city-ca-mau-680faa.webp', 'https://camau360.net/images/post/2024/10/cho_dem_ca_mau/cho_dem_ca_mau_ban_gi.webp']::TEXT[], 'Trải nghiệm mua sắm Cà Mau thể hiện nhịp sống thương mại của Cà Mau, từ chợ truyền thống đến cửa hàng hiện đại, nơi quà lưu niệm, đặc sản và dịch vụ mua sắm luôn nhộn nhịp.', 'entertainment'),
('Check-in cuối tuần tại Cà Mau', 'CMU', ARRAY['https://riviuhay.net/wp-content/uploads/2024/06/Untitled-2-17.jpg', 'https://luhanhvietnam.com.vn/du-lich/vnt_upload/news/06_2023/moc_diem_cuoi_duong_ho_chi_minh_ddd.png', 'https://booking.muongthanh.com/upload_images/images/H`/dia-diem-du-lich-ca-mau.jpg']::TEXT[], 'Check-in cuối tuần tại Cà Mau là lựa chọn vui chơi nhẹ nhàng ở Cà Mau, phù hợp cho những buổi hẹn, chuyến đi ngắn, chụp ảnh kỷ niệm và tận hưởng không khí cuối tuần.', 'entertainment'),
('Vườn quốc gia Tràm Chim', 'DTP', ARRAY['http://www.vietfuntravel.com.vn/image/data/Mekong/du-lich-dong-thap-vuon-quoc-gia-tram-chim-3.png', 'https://thamhiemmekong.com/wp-content/uploads/2019/12/vuon-quoc-gia-tram-chim-dong-thap-3.jpg', 'https://thamhiemmekong.com/wp-content/uploads/2019/04/vuon-quoc-gia-tram-chim-4.jpg']::TEXT[], 'Vườn quốc gia Tràm Chim nổi bật với cảnh quan thiên nhiên của Đồng Tháp, nơi địa hình núi rừng, thác nước, hang động hoặc tầng mây tạo nên vẻ đẹp hùng vĩ và nguyên sơ.', 'landmarks'),
